```cpp
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <iostream>

int main() {
    int pipefd[2];
    pid_t pid;

    if (pipe(pipefd) == -1) {
        std::cerr << "Erreur lors de la création du pipe" << std::endl;
        return 1;
    }

    pid = fork();

    if (pid == -1) {
        std::cerr << "Erreur lors de la création du processus fils" << std::endl;
        return 1;
    }

    if (pid == 0) { // Code du processus fils
        // Réduire l'entrée et la sortie standard à notre pipe
        dup2(pipefd[0], STDIN_FILENO);
        dup2(pipefd[1], STDOUT_FILENO);

        // Fermer les deux fins du pipe que le processus fils ne va pas utiliser
        close(pipefd[0]);
        close(pipefd[1]);

        std::cout << "Processus fils : Cela arrive après le redirige de la sortie standard." << std::endl;
    } else { // Code du processus père
        // Fermer les fins du pipe que le processus père ne va pas utiliser
        close(pipefd[0]);
        close(pipefd[1]);

        std::cout << "Processus père : Cela arrive avant de rediriger l'entrée standard." << std::endl;
    }

    return 0;
}
```

Cet exemple crée un pipe et utilise `fork()` pour créer un processus fils. Le processus fils redirige son entrée et sa sortie vers les fins du pipe, alors que le processus père ferme les fins du pipe qu'il ne nécessite pas.

